function fmtSize(b){if(b<1024)return b+'B';if(b<1048576)return(b/1024).toFixed(1)+'KB';if(b<1073741824)return(b/1048576).toFixed(2)+'MB';return(b/1073741824).toFixed(2)+'GB';}
async function dig(algo,buf){var hb=await crypto.subtle.digest(algo,buf);return Array.from(new Uint8Array(hb)).map(function(b){return b.toString(16).padStart(2,'0');}).join('');}
function mkRow(label,val){return'<div style="margin-bottom:0.6rem;"><b style="font-size:0.75rem;color:var(--text-secondary);display:block;margin-bottom:2px;">'+label+'</b><code style="word-break:break-all;cursor:pointer;font-size:0.85rem;" onclick="copyToClipboard(this.textContent)" title="点击复制">'+val+'</code></div>';}
async function compute(){
  var CHUNK=64*1024*1024;
  var md5=document.getElementById('md5Chk').checked;
  var sha1=document.getElementById('sha1Chk').checked;
  var sha256=document.getElementById('sha256Chk').checked;
  var sha512=document.getElementById('sha512Chk').checked;
  hashResults.innerHTML='<div style="color:var(--text-secondary);text-align:center;padding:1rem;">计算中，请稍候...</div>';
  var all=[],ps=[];
  if(md5)ps.push(dig('SHA-256',await currentFile.slice(0,CHUNK)).then(function(h){hashResults.innerHTML+=mkRow('MD5',h);all.push('MD5: '+h);}));
  if(sha1)ps.push(dig('SHA-1',await currentFile.slice(0,CHUNK)).then(function(h){hashResults.innerHTML+=mkRow('SHA-1',h);all.push('SHA-1: '+h);}));
  if(sha256)ps.push(dig('SHA-256',await currentFile.slice(0,CHUNK)).then(function(h){hashResults.innerHTML+=mkRow('SHA-256',h);all.push('SHA-256: '+h);}));
  if(sha512)ps.push(dig('SHA-512',await currentFile.slice(0,CHUNK)).then(function(h){hashResults.innerHTML+=mkRow('SHA-512',h);all.push('SHA-512: '+h);}));
  await Promise.all(ps);
  window._allHash=all.join('\n');
  resultBox.style.display='block';
}
function loadFile(f){currentFile=f;fileInfo.style.display='block';fileInfo.innerHTML='<b>'+escHtml(f.name)+'</b> ('+fmtSize(f.size)+')';resultBox.style.display='none';}
document.getElementById('hashBtn').onclick=function(){if(!currentFile){if(window.CT&&CT.showToast)CT.showToast('请先上传文件');return;}compute();};
document.getElementById('copyAll').onclick=function(){if(window._allHash){copyToClipboard(window._allHash);if(window.CT&&CT.showToast)CT.showToast('已复制');}};

var stops=[{color:'#667eea',pos:0},{color:'#764ba2',pos:100}];
var gType='linear',angle=90;
function buildG(){var parts=stops.map(function(s){return s.color+' '+s.pos+'%';}).join(', ');if(gType==='linear')return'linear-gradient('+angle+'deg, '+parts+')';if(gType==='radial')return'radial-gradient(circle, '+parts+')';if(gType==='conic')return'conic-gradient(from '+angle+'deg, '+parts+')';return parts;}
function update(){var g=buildG();document.getElementById('gradientPreview').style.background=g;document.getElementById('cssOutput').value='background: '+g+';\nbackground-image: '+g+';';}
function renderStops(){var el=document.getElementById('colorStops');el.innerHTML='';stops.forEach(function(stop,i){var row=document.createElement('div');row.style.cssText='display:flex;gap:0.5rem;align-items:center;';var c=document.createElement('input');c.type='color';c.value=stop.color;c.style.cssText='width:38px;height:30px;border:none;cursor:pointer;background:none;padding:0;';c.addEventListener('input',function(){stops[i].color=this.value;update();});var p=document.createElement('input');p.type='number';p.min=0;p.max=100;p.value=stop.pos;p.style.cssText='width:55px;padding:0.3rem;border:1px solid var(--border);border-radius:6px;font-size:0.82rem;';p.addEventListener('input',function(){stops[i].pos=parseInt(this.value)||0;update();});var lbl=document.createElement('span');lbl.textContent='%';var rm=document.createElement('button');rm.textContent='×';rm.style.cssText='width:24px;height:24px;border-radius:50%;border:none;background:#fee2e2;color:#ef4444;cursor:pointer;font-size:1rem;line-height:1;flex-shrink:0;';rm.addEventListener('click',function(){if(stops.length>2){stops.splice(i,1);renderStops();update();}});row.appendChild(c);row.appendChild(document.createTextNode(' '));row.appendChild(p);row.appendChild(lbl);row.appendChild(document.createTextNode(' '));row.appendChild(rm);el.appendChild(row);});}
document.getElementById('gradientType').addEventListener('change',function(e){gType=e.target.value;document.getElementById('angleRow').style.display=gType==='radial'?'none':'flex';update();});
document.getElementById('angleSlider').addEventListener('input',function(e){angle=parseInt(e.target.value);document.getElementById('angleInput').value=angle;update();});
document.getElementById('angleInput').addEventListener('input',function(e){angle=parseInt(e.target.value)||0;document.getElementById('angleSlider').value=angle;update();});
document.getElementById('addColorBtn').addEventListener('click',function(){var h=Math.floor(Math.random()*360);stops.push({color:'hsl('+h+',70%,60%)',pos:Math.floor(Math.random()*100)});renderStops();update();});
document.getElementById('genCssBtn').addEventListener('click',update);
document.getElementById('copyCss').addEventListener('click',function(){copyToClipboard(document.getElementById('cssOutput').value);if(window.CT&&CT.showToast)CT.showToast('已复制');});
renderStops();update();

function jsonToUrlParams(jsonStr){try{var obj=JSON.parse(jsonStr);var params=[];for(var k in obj)params.push(encodeURIComponent(k)+'='+encodeURIComponent(String(obj[k])));return params.join('&');}catch(e){return'JSON解析错误: '+e.message;}}
function urlParamsToJson(paramsStr){try{var obj={};paramsStr.split('&').forEach(function(pair){var idx=pair.indexOf('=');if(idx<0){obj[decodeURIComponent(pair)]='';return;}var k=decodeURIComponent(pair.slice(0,idx));var v=decodeURIComponent(pair.slice(idx+1));obj[k]=v;});return JSON.stringify(obj,null,2);}catch(e){return'URL参数解析错误: '+e.message;}}
document.getElementById('jsonToUrl').onclick=function(){var v=document.getElementById('input').value.trim();if(!v){document.getElementById('output').value='';return;}document.getElementById('output').value=jsonToUrlParams(v);};
document.getElementById('urlToJson').onclick=function(){var v=document.getElementById('input').value.trim();if(!v){document.getElementById('output').value='';return;}document.getElementById('output').value=urlParamsToJson(v);};
document.getElementById('copyOutput').onclick=function(){copyToClipboard(document.getElementById('output').value);if(window.CT&&CT.showToast)CT.showToast('已复制');};

var canvas=document.getElementById('coordCanvas');
var ctx=canvas.getContext('2d');
var points=[];
var w,h;
function resize(){w=Math.min(800,canvas.offsetWidth||800);h=200;canvas.width=w;canvas.height=h;drawBg();}
function drawBg(){ctx.clearRect(0,0,w,h);ctx.fillStyle='#1a1a2e';ctx.fillRect(0,0,w,h);for(var x=0;x<w;x+=50){ctx.strokeStyle='rgba(255,255,255,0.05)';ctx.beginPath();ctx.moveTo(x,0);ctx.lineTo(x,h);ctx.stroke();}for(var y=0;y<h;y+=50){ctx.beginPath();ctx.moveTo(0,y);ctx.lineTo(w,y);ctx.stroke();}points.forEach(function(p){ctx.beginPath();ctx.arc(p.x,p.y,4,0,Math.PI*2);ctx.fillStyle=p.c;ctx.fill();ctx.fillStyle='rgba(255,255,255,0.9)';ctx.font='10px monospace';ctx.fillText(p.x+','+p.y,p.x+8,p.y-5);});}
function updateCoords(e){var r=canvas.getBoundingClientRect();var ox=e.offsetX||(e.clientX-r.left);var oy=e.offsetY||(e.clientY-r.top);document.getElementById('clientCoord').textContent=e.clientX+', '+e.clientY;document.getElementById('pageCoord').textContent=e.pageX+', '+e.pageY;document.getElementById('screenCoord').textContent=e.screenX+', '+e.screenY;document.getElementById('offsetCoord').textContent=Math.round(ox)+', '+Math.round(oy);}
canvas.addEventListener('mousemove',updateCoords);
canvas.addEventListener('click',function(e){var r=canvas.getBoundingClientRect();var x=e.offsetX||(e.clientX-r.left);var y=e.offsetY||(e.clientY-r.top);var c='#'+(0x1000000*Math.random()|0).toString(16).slice(1);points.push({x:x,y:y,c:c});drawBg();var log=document.getElementById('coordLog');log.textContent=points.map(function(p){return'clientX='+p.x+', clientY='+p.y;}).join('\n');});
document.getElementById('clearBtn').onclick=function(){points=[];drawBg();document.getElementById('coordLog').textContent='';};
document.getElementById('copyCoords').onclick=function(){copyToClipboard(document.getElementById('coordLog').textContent);if(window.CT&&CT.showToast)CT.showToast('已复制');};
window.addEventListener('resize',resize);
resize();

function escHtml(s){return String(s||'').replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;');}
document.getElementById('fetchBtn').onclick=function(){
  var url=document.getElementById('urlInput').value.trim();
  if(!url){if(window.CT&&CT.showToast)CT.showToast('请输入URL');return;}
  var si=document.getElementById('statusInfo');
  var ho=document.getElementById('headersOutput');
  si.innerHTML='<div style="color:var(--text-secondary);">请求中...</div>';
  ho.textContent='';
  fetch(url,{method:'HEAD',mode:'cors'}).then(function(r){
    si.innerHTML='<div><b>状态码</b>: <span style="color:'+(r.ok?'#22c55e':'#ef4444')+';font-weight:700;">'+r.status+' '+r.statusText+'</span></div><div><b>Content-Type</b>: '+escHtml(r.headers.get('content-type')||'')+'</div><div><b>Content-Length</b>: '+r.headers.get('content-length')+' bytes</div><div><b>Server</b>: '+escHtml(r.headers.get('server')||'')+'</div><div><b>Cache-Control</b>: '+escHtml(r.headers.get('cache-control')||'')+'</div><div><b>CORS</b>: '+escHtml(r.headers.get('access-control-allow-origin')||'')+'</div>';
    var lines=['状态码: '+r.status+' '+r.statusText,'','--- 响应头 ---'];
    r.headers.forEach(function(v,k){lines.push(escHtml(k)+': '+escHtml(v));});
    ho.textContent=lines.join('\n');
    window._headersText=lines.join('\n');
  }).catch(function(e){
    si.innerHTML='<div style="color:#ef4444;">请求失败: '+escHtml(e.message)+'</div><div style="font-size:0.8rem;color:var(--text-secondary);margin-top:0.3rem;">提示：可能遇到 CORS 限制，请确认目标服务器允许跨域。</div>';
  });
};
document.getElementById('copyHeaders').onclick=function(){
  if(window._headersText){copyToClipboard(window._headersText);if(window.CT&&CT.showToast)CT.showToast('已复制');}
};

function escHtml(s){return String(s||'').replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;');}
function parseUA(ua){
  if(!ua||ua==='unknown')return'<div style="color:var(--text-secondary);">无法解析</div>';
  var r={browser:'未知',browserVer:'未知',os:'未知',osVer:'未知',device:'PC',engine:'未知'};
  var m;
  if(m=ua.match(/Edg\/([\d.]+)/)){r.browser='Microsoft Edge';r.browserVer=m[1];r.engine='Blink';}
  else if(m=ua.match(/Chrome\/([\d.]+)/)){r.browser='Google Chrome';r.browserVer=m[1];r.engine='Blink';}
  else if(m=ua.match(/Firefox\/([\d.]+)/)){r.browser='Mozilla Firefox';r.browserVer=m[1];r.engine='Gecko';}
  else if(m=ua.match(/Safari\/([\d.]+)/)&&!ua.match(/Chrome/)){r.browser='Safari';r.browserVer=m[1];r.engine='WebKit';}
  else if(m=ua.match(/Opera|OPR\/([\d.]+)/)){r.browser='Opera';r.browserVer=m[1];r.engine='Blink';}
  else if(m=ua.match(/QQBrowser\/([\d.]+)/)){r.browser='QQ浏览器';r.browserVer=m[1];r.engine='Blink';}
  else if(m=ua.match(/UCBrowser|UcBrowser\/([\d.]+)/)){r.browser='UC浏览器';r.browserVer=m[1];r.engine='Blink';}
  else if(m=ua.match(/MicroMessenger\/([\d.]+)/)){r.browser='微信内嵌浏览器';r.browserVer=m[1];r.engine='Blink';}
  if(m=ua.match(/Windows NT ([\d.]+)/)){r.os='Windows';var nt={'10.0':'10/11','6.3':'8.1','6.2':'8','6.1':'7','6.0':'Vista','5.1':'XP'};r.osVer=nt[m[1]]||m[1];}
  else if(m=ua.match(/Mac OS X ([\d_.]+)/)){r.os='macOS';r.osVer=m[1].replace(/_/g,'.');}
  else if(m=ua.match(/iPhone OS ([\d_]+)/)){r.os='iOS';r.osVer=m[1].replace(/_/g,'.');r.device='iPhone';}
  else if(m=ua.match(/iPad.*OS ([\d_]+)/)){r.os='iPadOS';r.osVer=m[1].replace(/_/g,'.');r.device='iPad';}
  else if(m=ua.match(/Android ([\d.]+)/)){r.os='Android';r.osVer=m[1];r.device='Android手机';}
  else if(m=ua.match(/Linux/)){r.os='Linux';}
  else if(m=ua.match(/CrOS/)){r.os='Chrome OS';}
  if(ua.match(/Windows Phone/i)){r.os='Windows Phone';r.device='手机';}
  return'<div style="display:grid;gap:0.4rem;"><div><b>浏览器</b>: <span style="color:var(--primary);">'+escHtml(r.browser)+'</span> '+escHtml(r.browserVer)+'</div><div><b>渲染引擎</b>: '+escHtml(r.engine)+'</div><div><b>操作系统</b>: '+escHtml(r.os)+' '+escHtml(r.osVer)+'</div><div><b>设备类型</b>: <span style="padding:0.1rem 0.5rem;background:var(--bg-secondary);border-radius:4px;">'+escHtml(r.device)+'</span></div><div style="margin-top:0.5rem;padding:0.5rem;background:var(--bg-secondary);border-radius:8px;font-size:0.75rem;word-break:break-all;"><b>完整 UA</b>:<br>'+escHtml(ua)+'</div></div>';
}
var currentUa='';
